## 테스트 전략 (Test Skill)

### 1. 단위 테스트 (Service Layer)

```kotlin
@ExtendWith(MockitoExtension::class)
class NotificationServiceTest {
    @Mock
    private lateinit var repository: NotificationRepository
    @InjectMocks
    private lateinit var service: NotificationService

    @Test
    fun `should return notifications by userId`() {
        // given
        val userId = "test-user-id"
        val entities = listOf(
            NotificationEntity(id = "1", userId = userId, type = "FOLLOW", message = "test")
        )
        `when`(repository.findByUserIdOrderByCreatedAtDesc(userId)).thenReturn(entities)

        // when
        val result = service.getNotifications(userId)

        // then
        assertThat(result).hasSize(1)
        assertThat(result[0].message).isEqualTo("test")
        verify(repository).findByUserIdOrderByCreatedAtDesc(userId)
    }

    @Test
    fun `should throw when notification not found`() {
        assertThrows<NotFoundException> {
            service.getNotificationById("invalid")
        }
    }
}
```

### 2. gRPC Service 테스트

```kotlin
@ExtendWith(MockitoExtension::class)
class NotificationGrpcServiceTest {
