## GraphQL 스키마 설계 (GraphQL Skill)

### Notification Schema

```graphql
type Notification {
    id: ID!
    userId: String!
    type: NotificationType!
    targetId: String
    message: String!
    isRead: Boolean!
    metadata: String
    createdAt: String!
    updatedAt: String!
}

type NotificationSetting {
    id: ID!
    userId: String!
    notificationType: NotificationType!
    isEnabled: Boolean!
    channel: NotificationChannel!
    createdAt: String!
    updatedAt: String!
}

enum NotificationType {
    FOLLOW
    MESSAGE
    CALL
    LIKE
    COMMENT
    SYSTEM
}

enum NotificationChannel {
    PUSH
    EMAIL
    SMS
    IN_APP
}

input CreateNotificationInput {
    type: NotificationType!
    targetId: String
    message: String!
}

input UpdateNotificationSettingInput {
    notificationType: NotificationType!
    isEnabled: Boolean!
    channel: NotificationChannel!
}

extend type Query {
    notification(notificationId: ID!): Notification
    notifications(limit: Int, offset: Int): [Notification!]!
    unreadNotifications(limit: Int): [Notification!]!
    notificationSettings: [NotificationSetting!]!
}

extend type Mutation {
    markAsRead(notificationId: ID!): Boolean!
    markAllAsRead: Boolean!
    deleteNotification(notificationId: ID!): Boolean!
    updateNotificationSetting(input: UpdateNotificationSettingInput!): NotificationSetting!
}
```

