## gRPC Proto 설계 (gRPC Skill)

### notification.proto

```protobuf
syntax = "proto3";
package notification;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.notification";

service NotificationService {
  rpc GetNotification(GetNotificationRequest) returns (GetNotificationResponse);
  rpc CreateNotification(CreateNotificationRequest) returns (CreateNotificationResponse);
  rpc ListNotifications(ListNotificationsRequest) returns (ListNotificationsResponse);
  rpc MarkAsRead(MarkAsReadRequest) returns (MarkAsReadResponse);
  rpc GetSettings(GetSettingsRequest) returns (GetSettingsResponse);
  rpc UpdateSetting(UpdateSettingRequest) returns (UpdateSettingResponse);
}

message GetNotificationRequest {
  string user_id = 1;
  string notification_id = 2;
}

message GetNotificationResponse {
  Notification notification = 1;
}

message CreateNotificationRequest {
  string user_id = 1;
  string type = 2;
  optional string target_id = 3;
  string message = 4;
  optional string metadata = 5;
}

message CreateNotificationResponse {
  Notification notification = 1;
}

message ListNotificationsRequest {
  string user_id = 1;
  int32 limit = 2;
  int32 offset = 3;
  optional bool unread_only = 4;
}

message ListNotificationsResponse {
  repeated Notification notifications = 1;
  int32 total = 2;
}

message MarkAsReadRequest {
  string notification_id = 1;
}

message MarkAsReadResponse {
  bool success = 1;
}

message Notification {
  string id = 1;
  string user_id = 2;
  string type = 3;
  optional string target_id = 4;
  string message = 5;
  bool is_read = 6;
  optional string metadata = 7;
  string created_at = 8;
}

message GetSettingsRequest {
  string user_id = 1;
}

message GetSettingsResponse {
  repeated NotificationSetting settings = 1;
}

message UpdateSettingRequest {
  string user_id = 1;
  string notification_type = 2;
  bool is_enabled = 3;
  string channel = 4;
}

message UpdateSettingResponse {
  NotificationSetting setting = 1;
}

message NotificationSetting {
  string id = 1;
  string user_id = 2;
  string notification_type = 3;
  bool is_enabled = 4;
  string channel = 5;
}
